mapper.select:
SELECT
    *
FROM im_message
WHERE
      conversation_id = #{conversationId}

      AND conversation_type = #{conversationType}

  AND server_seq > #{maxSeq}
  AND status = 1  -- 正常状态的消息
  AND is_recalled = 0  -- 未撤回的消息
ORDER BY server_seq DESC
    LIMIT #{limit}

SELECT COUNT(1)
FROM im_message
WHERE
    conversation_id = #{conversationId}

    AND conversation_type = #{conversationType}

AND server_seq > #{maxSeq}
AND status = 1
AND is_recalled = 0

SELECT MAX(server_seq)
FROM im_message
WHERE conversation_type = #{conversationType}
  AND conversation_id = #{conversationId}
  AND status = 1
